assign multi = inp_north * inp_west; 
always @(posedge rst or posedge clk) begin 
    if(rst) begin 
        result <= 0; 
        outp_east <= 0; 
        outp_south <= 0; 
    end 
    else begin 
        result <= multi; 
        outp_east <= inp_west; 
        outp_south <= inp_north; 
    end 
end

always @(posedge clk or posedge rst) begin
    if(!rst) begin
        done <= 0;
        count <= 0;
    end
    else begin
        if(count == 15) begin // changed from 9 to 15
            done <= 1;
            count <= 0;
        end
        else begin
            done <= 0;
            count <= count + 1;
        end
    end
end
